  console.log("[parse-story] ERROR: Input is null/undefined");
  return [];
}

if (typeof text === "object") {
  text = text.text || text.content || text.response || text.message || JSON.stringify(text);
}
if (typeof text !== "string") {
  text = String(text);
}

try {
  // Remove potential thinking tags, markdown code blocks, etc.
  text = text.replace(/<think[^>]*>[\s\S]*?<\/think[^>]*>/gi, "");
  text = text.replace(/<thinking[^>]*>[\s\S]*?<\/thinking[^>]*>/gi, "");
  text = text.replace(/```json\s*/gi, "");
  text = text.replace(/```\s*/gi, "");
  text = text.trim();

  let startIdx = text.indexOf("{");
  let endIdx = text.lastIndexOf("}");
  console.log("[parse-story] JSON bounds: start=", startIdx, "end=", endIdx);

  if (startIdx >= 0 && endIdx > startIdx) {
    text = text.substring(startIdx, endIdx + 1);
  }

  console.log("[parse-story] Extracted length:", text.length);
  console.log("[parse-story] First 500 chars:", text.substring(0, 500));

  // Parse the JSON
