  console.log("[parse-story] for-in keys:", storyKeys.join(", "));
  console.log("[parse-story] title via dot:", story.title);
  console.log("[parse-story] title via bracket:", story["title"]);

  // Extract characters - create a new array to ensure it's a proper array
  let characters = [];
