  console.log("[parse-story] characters extracted:", characters.length);

  // Extract scenes - create a new array to ensure it's a proper array
  let scenes = [];
  let storyScenes = story.scenes || story["scenes"];
  console.log("[parse-story] storyScenes exists:", !!storyScenes);
  console.log("[parse-story] storyScenes type:", typeof storyScenes);
  if (storyScenes) {
    console.log("[parse-story] storyScenes is array:", Array.isArray(storyScenes));
    console.log("[parse-story] storyScenes length:", storyScenes.length);
    for (let i = 0; i < storyScenes.length; i++) {
