      scenes.push(scene);
      let sceneTitle = scene.title || scene["title"];
      console.log("[parse-story] Added scene:", scene.number || i, sceneTitle || "untitled");
    }
  }
  console.log("[parse-story] scenes extracted:", scenes.length);

  if (characters.length > 0) {
    console.log("[parse-story] First character:", JSON.stringify(characters[0]));
  }
  if (scenes.length > 0) {
    let firstTitle = scenes[0].title || scenes[0]["title"];
    let firstPrompt = scenes[0].start_image_prompt || scenes[0]["start_image_prompt"] || scenes[0].startImagePrompt || "none";
    console.log("[parse-story] First scene title:", firstTitle);
