// Process TTS results and calculate frame counts per scene
// Uses Audio.getAudioDuration() to get actual audio duration from files
let ttsResults = input;
let fps = 25;
let sceneDurations = [];
let sceneFrameCounts = [];
let ttsDurations = [];
let totalDuration = 0;
let numScenes = ttsResults.length;
let endPaddingSeconds = 4;

console.log("[process-tts-results] TTS results:", ttsResults);
console.log("[process-tts-results] Number of scenes:", numScenes);

for (let i = 0; i < numScenes; i = i + 1) {
  let result = ttsResults[i];
  let durationMs = 0;
  let audioPath = null;

  // TTS returns objects like {audio, path, durationMs} or strings
  if (result && typeof result === "object") {
    // Try to get duration from object first
    durationMs = result.durationMs || 0;
    // Get path for fallback duration detection
    audioPath = result.path || result.audio || null;
    console.log("[process-tts-results] Object result - durationMs:", durationMs, "path:", audioPath);
  } else if (result && typeof result === "string") {
    audioPath = result;
    console.log("[process-tts-results] String result:", audioPath);
  }

  // If no duration from object, use ffprobe to get it from file
  if (durationMs <= 0 && audioPath) {
    console.log("[process-tts-results] Getting duration via ffprobe for:", audioPath);
    durationMs = await Audio.getAudioDuration(audioPath);
    console.log("[process-tts-results] Duration from ffprobe:", durationMs, "ms");
  }

  // Fallback if duration detection failed
  if (durationMs <= 0) {
    console.log("[process-tts-results] Duration detection failed, using fallback 5000ms");
    durationMs = 5000;
  }

  let ttsDurationSec = durationMs / 1000;
  ttsDurations.push(ttsDurationSec);

  // Calculate frame count: duration * fps (25fps for video)
  let frameCount = Math.ceil(ttsDurationSec * fps);
  // Clamp frame count to reasonable range
  if (frameCount < 72) frameCount = 72;
  if (frameCount > 300) frameCount = 300;

  console.log("[process-tts-results] Scene", i, ": duration=", ttsDurationSec, "s, frames=", frameCount);

  let isLastScene = (i === numScenes - 1);
  let targetDuration = ttsDurationSec;
  if (isLastScene) {
    targetDuration = targetDuration + endPaddingSeconds;
  }

  sceneDurations.push(targetDuration);
  sceneFrameCounts.push(frameCount);
  totalDuration = totalDuration + targetDuration;
}

